import React, { useState } from "react";
import axios from "axios";
import "./BuyActionWindow.css";

const BuyActionWindow = ({ uid, onClose }) => {
  const [stockQuantity, setStockQuantity] = useState(1);
  const [stockPrice, setStockPrice] = useState(0);

  const handleBuyClick = async () => {
    if (!uid) {
      alert("Stock name is missing.");
      return;
    }

    try {
      const res = await axios.post("http://localhost:3002/newOrder", {
        name: uid,
        qty: stockQuantity,
        price: stockPrice,
        mode: "BUY",
      });

      console.log("✅ Order placed:", res.data);
      onClose && onClose();
    } catch (err) {
      console.error("❌ Error placing order:", err);
      alert("Failed to place order. Please try again.");
    }
  };

  return (
    <div className="buy-window">
      <div className="order-inputs">
        <label>
          Qty:
          <input
            type="number"
            value={stockQuantity}
            onChange={(e) => setStockQuantity(Number(e.target.value))}
            min="1"
          />
        </label>
        <label>
          Price:
          <input
            type="number"
            step="0.05"
            value={stockPrice}
            onChange={(e) => setStockPrice(Number(e.target.value))}
            min="0"
          />
        </label>
      </div>

      <div className="order-actions">
        <span>Margin: ₹{(stockQuantity * stockPrice).toFixed(2)}</span>
        <button className="btn btn-blue" onClick={handleBuyClick}>
          Buy
        </button>
        <button className="btn btn-grey" onClick={onClose}>
          Cancel
        </button>
      </div>
    </div>
  );
};

export default BuyActionWindow;
